int counter = 0;
int btnIncPin = 9;
int btnDecPin = 10;
int lastIncState = HIGH;
int lastDecState = HIGH;

int segA = 2, segB = 3, segC = 4, segD = 5, segE = 6, segF = 7, segG = 8;

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  pinMode(btnIncPin, INPUT_PULLUP);
  pinMode(btnDecPin, INPUT_PULLUP);
  displayNumber(counter);
}

void displayNumber(int n) {
  int a, b, c, d, e, f, g;

  if (n == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (n == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (n == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (n == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (n == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (n == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (n == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (n == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (n == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (n == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  int incState = digitalRead(btnIncPin);
  int decState = digitalRead(btnDecPin);

  if (incState == LOW && lastIncState == HIGH) {
    if (counter < 9) {
      counter++;
    }
    displayNumber(counter);
    delay(50);
  }

  if (decState == LOW && lastDecState == HIGH) {
    if (counter > 0) {
      counter--;
    }
    displayNumber(counter);
    delay(50);
  }

  lastIncState = incState;
  lastDecState = decState;
  delay(10);
}

